1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	  <meta charset="UTF-8" />
5	  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
6	  <title>{{userName}}</title>
7	  <style>
8	    :root {
9	      --bg: #09090b;
10	      --surface: #131316;
11	      --text: #ededf0;
12	      --muted: #8b8b96;
13	      --accent: #5eead4;
14	      --accent-2: #a78bfa;
15	      --border: #232329;
16	      --gp-highlight: #fbbf24;
17	    }
18	
19	    * {
20	      margin: 0;
21	      padding: 0;
22	      box-sizing: border-box;
23	    }
24	
25	    html {
26	      scroll-behavior: smooth;
27	    }
28	
29	    ::selection {
30	      background: rgba(94, 234, 212, 0.25);
31	    }
32	
33	    body {
34	      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
35	      background: var(--bg);
36	      color: var(--text);
37	      line-height: 1.6;
38	      -webkit-font-smoothing: antialiased;
39	    }
40	
41	    .container {
42	      max-width: 720px;
43	      margin: 0 auto;
44	      padding: 0 24px;
45	    }
46	
47	    /* Header / hero */
48	    header {
49	      position: relative;
50	      padding: 96px 0 64px;
51	    }
52	
53	    header::before {
54	      content: "";
55	      position: absolute;
56	      top: -160px;
57	      left: -120px;
58	      width: 480px;
59	      height: 480px;
60	      background: radial-gradient(circle, rgba(94, 234, 212, 0.08), transparent 70%);
61	      pointer-events: none;
62	    }
63	
64	    .avatar {
65	      width: 88px;
66	      height: 88px;
67	      border-radius: 50%;
68	      background: linear-gradient(135deg, var(--accent), var(--accent-2));
69	      display: flex;
70	      align-items: center;
71	      justify-content: center;
72	      font-size: 32px;
73	      font-weight: 700;
74	      color: var(--bg);
75	      margin-bottom: 24px;
76	      box-shadow: 0 0 40px rgba(94, 234, 212, 0.25);
77	    }
78	
79	    h1 {
80	      font-size: 40px;
81	      font-weight: 700;
82	      letter-spacing: -0.02em;
83	      margin-bottom: 8px;
84	    }
85	
86	    .tagline {
87	      font-size: 20px;
88	      color: var(--muted);
89	      margin-bottom: 24px;
90	    }
91	
92	    .intro {
93	      font-size: 17px;
94	      color: var(--text);
95	      max-width: 60ch;
96	    }
97	
98	    .cta-button {
99	      display: inline-block;
100	      margin-top: 28px;
101	      padding: 12px 24px;
102	      background: var(--gp-highlight);
103	      border-radius: 999px;
104	      color: var(--bg);
105	      font-size: 16px;
106	      font-weight: 600;
107	      text-decoration: none;
108	      transition: filter 0.15s ease;
109	    }
110	
111	    .cta-button:hover {
112	      filter: brightness(1.1);
113	    }
114	
115	    /* Sections */
116	    section {
117	      padding: 40px 0;
118	      border-top: 1px solid var(--border);
119	    }
120	
121	    h2 {
122	      font-size: 14px;
123	      font-weight: 600;
124	      text-transform: uppercase;
125	      letter-spacing: 0.08em;
126	      color: var(--muted);
127	      margin-bottom: 24px;
128	    }
129	
130	    /* Work / projects */
131	    .section-note {
132	      font-size: 16px;
133	      color: var(--muted);
134	      max-width: 60ch;
135	    }
136	
137	    .section-note a {
138	      color: var(--accent);
139	      text-decoration: none;
140	    }
141	
142	    .section-note a:hover {
143	      text-decoration: underline;
144	    }
145	
146	    /* Skills */
147	    .skills {
148	      display: grid;
149	      grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
150	      gap: 16px;
151	    }
152	
153	    .skill {
154	      background: var(--surface);
155	      border: 1px solid var(--border);
156	      border-radius: 12px;
157	      padding: 20px 24px;
158	    }
159	
160	    .skill h3 {
161	      font-size: 16px;
162	      font-weight: 600;
163	      margin-bottom: 4px;
164	    }
165	
166	    .skill p {
167	      font-size: 14px;
168	      color: var(--muted);
169	    }
170	
171	    /* Testimonials */
172	    .testimonial-card {
173	      background: var(--surface);
174	      border: 1px solid var(--border);
175	      border-radius: 12px;
176	      padding: 24px;
177	      margin-bottom: 16px;
178	    }
179	
180	    .testimonial-card:last-child {
181	      margin-bottom: 0;
182	    }
183	
184	    .testimonial-card blockquote {
185	      font-size: 16px;
186	      font-style: italic;
187	      margin-bottom: 12px;
188	    }
189	
190	    .testimonial-card cite {
191	      font-size: 14px;
192	      font-style: normal;
193	      color: var(--muted);
194	    }
195	
196	    /* Contact links */
197	    .links {
198	      display: flex;
199	      flex-wrap: wrap;
200	      gap: 12px;
201	    }
202	
203	    .links a {
204	      display: inline-block;
205	      padding: 10px 18px;
206	      border: 1px solid var(--border);
207	      border-radius: 999px;
208	      color: var(--text);
209	      text-decoration: none;
210	      font-size: 15px;
211	      transition: border-color 0.15s ease, color 0.15s ease;
212	    }
213	
214	    .links a:hover {
215	      border-color: var(--accent);
216	      color: var(--accent);
217	    }
218	
219	    footer {
220	      padding: 40px 0 64px;
221	      border-top: 1px solid var(--border);
222	      color: var(--muted);
223	      font-size: 14px;
224	    }
225	
226	    @media (max-width: 480px) {
227	      header {
228	        padding: 64px 0 48px;
229	      }
230	
231	      h1 {
232	        font-size: 32px;
233	      }
234	
235	      .tagline {
236	        font-size: 18px;
237	      }
238	    }
239	  </style>
240	</head>
241	<body>
242	  <div class="container">
243	    <header>
244	      <div class="avatar">AK</div>
245	      <h1>{{userName}}</h1>
246	      <p class="tagline">Software engineer &amp; builder</p>
247	      <p class="intro">
248	        Hi, I'm {{userName}}. I build software and enjoy turning ideas into simple,
249	        well-crafted tools. This is my corner of the internet — a place for
250	        what I'm working on and how to reach me.
251	      </p>
252	      <a class="cta-button" href="#contact">Get in Touch</a>
253	    </header>
254	
255	    <section>
256	      <h2>What I'm working on</h2>
257	      <p class="section-note">
258	        I'm always building something — new projects will land here soon.
259	        In the meantime, you can find my work on
260	        <a href="https://github.com/" target="_blank" rel="noopener">GitHub</a>.
261	      </p>
262	    </section>
263	
264	    <section>
265	      <h2>Skills</h2>
266	      <div class="skills">
267	        <div class="skill">
268	          <h3>Web Development</h3>
269	          <p>Building responsive, accessible sites with modern HTML, CSS, and JavaScript.</p>
270	        </div>
271	        <div class="skill">
272	          <h3>Backend &amp; APIs</h3>
273	          <p>Designing and shipping reliable services, from data models to deployment.</p>
274	        </div>
275	        <div class="skill">
276	          <h3>Developer Tooling</h3>
277	          <p>Automating workflows and crafting small tools that make teams faster.</p>
278	        </div>
279	      </div>
280	    </section>
281	
282	    <section>
283	      <h2>Testimonials</h2>
284	      <div class="testimonial-card">
285	        <blockquote>&ldquo;{{userName}} turned a vague idea into a working product in weeks. Clear communication, clean code, and no surprises.&rdquo;</blockquote>
286	        <cite>&mdash; Jordan Lee, Product Manager</cite>
287	      </div>
288	      <div class="testimonial-card">
289	        <blockquote>&ldquo;One of the most reliable engineers I've worked with. The tooling they built saved our team hours every single week.&rdquo;</blockquote>
290	        <cite>&mdash; Sam Rivera, Engineering Lead</cite>
291	      </div>
292	    </section>
293	
294	    <section id="contact">
295	      <h2>Get in touch</h2>
296	      <div class="links">
297	        <a href="mailto:<email>">Email</a>
298	        <a href="https://github.com/" target="_blank" rel="noopener">GitHub</a>
299	        <a href="https://www.linkedin.com/" target="_blank" rel="noopener">LinkedIn</a>
300	      </div>
301	    </section>
302	
303	    <footer>
304	      &copy; 2026 {{userName}}
305	    </footer>
306	  </div>
307	</body>
308	</html>
